final:
module top_module(
  input [3:0] in,
  output reg out
);integer i;
  wire [3:0] _tap_in = in & {4{1'b1}};

  reg [1:0] count;

  always @(*) begin
    count = 0;
    for (i = 0; i < 4; i = i + 1) begin
      count = count + in[i];
    end
    out = (count % 2 == 0) ? 1'b0 : 1'b1;
  end

endmodule
